import{_ as p,c as o}from"./app.90a21e26.js";const t={},l=o('<h1 id="_15-\u8BB2-\u8FC7\u4E0D\u4E86\u7684\u574E-\u804A\u804A-gui-\u81EA\u52A8\u5316\u8FC7\u7A0B\u4E2D\u7684\u6D4B\u8BD5\u6570\u636E" tabindex="-1"><a class="header-anchor" href="#_15-\u8BB2-\u8FC7\u4E0D\u4E86\u7684\u574E-\u804A\u804A-gui-\u81EA\u52A8\u5316\u8FC7\u7A0B\u4E2D\u7684\u6D4B\u8BD5\u6570\u636E" aria-hidden="true">#</a> 15 \u8BB2\uFF1A\u8FC7\u4E0D\u4E86\u7684\u574E\uFF1A\u804A\u804A GUI \u81EA\u52A8\u5316\u8FC7\u7A0B\u4E2D\u7684\u6D4B\u8BD5\u6570\u636E</h1><p>\u5728\u524D\u9762\u51E0\u7BC7\u6587\u7AE0\u4E2D\uFF0C\u6211\u4ECE\u9875\u9762\u64CD\u4F5C\u7684\u89D2\u5EA6\u4ECB\u7ECD\u4E86 GUI \u81EA\u52A8\u5316\u6D4B\u8BD5\uFF0C\u8BB2\u89E3\u4E86\u9875\u9762\u5BF9\u8C61\u6A21\u578B\u548C\u4E1A\u52A1\u6D41\u7A0B\u5C01\u88C5\uFF0C\u4ECA\u5929\u6211\u5C06\u4ECE\u6D4B\u8BD5\u6570\u636E\u7684\u89D2\u5EA6\u518D\u6765\u8C08\u8C08 GUI \u81EA\u52A8\u5316\u6D4B\u8BD5\u3002</p><p>\u4E3A\u4E86\u987A\u5229\u8FDB\u884C GUI \u6D4B\u8BD5\uFF0C\u5F80\u5F80\u9700\u8981\u51C6\u5907\u6D4B\u8BD5\u6570\u636E\u6765\u914D\u5408\u6D4B\u8BD5\u7684\u8FDB\u884C\uFF0C\u5982\u679C\u4E0D\u91C7\u7528\u4E8B\u5148\u6570\u636E\u51C6\u5907\u7684\u65B9\u5F0F\uFF0C\u6D4B\u8BD5\u6548\u7387\u5C06\u4F1A\u5927\u6253\u6298\u6263\uFF0C\u800C\u4E14\u8FD8\u4F1A\u5F15\u5165\u5927\u91CF\u4E0D\u5FC5\u8981\u7684\u4F9D\u8D56\u5173\u7CFB\u3002</p><p>\u4EE5\u201C\u7528\u6237\u767B\u5F55\u201D\u529F\u80FD\u7684\u6D4B\u8BD5\u4E3A\u4F8B\uFF0C\u5982\u679C\u4F60\u7684\u76EE\u7684\u4EC5\u4EC5\u662F\u6D4B\u8BD5\u7528\u6237\u662F\u5426\u53EF\u4EE5\u6B63\u5E38\u767B\u5F55\uFF0C\u6BD4\u8F83\u7406\u60F3\u7684\u65B9\u5F0F\u662F\u8FD9\u4E2A\u7528\u6237\u5DF2\u7ECF\u5B58\u5728\u4E8E\u88AB\u6D4B\u7CFB\u7EDF\u4E2D\u4E86\uFF0C\u6216\u8005\u4F60\u53EF\u4EE5\u901A\u8FC7\u5F88\u65B9\u4FBF\u7684\u65B9\u5F0F\u5728\u6D4B\u8BD5\u7528\u4F8B\u4E2D\u751F\u6210\u8FD9\u4E2A\u7528\u6237\u3002\u5426\u5219\uFF0C\u96BE\u9053\u4F60\u8981\u4E3A\u4E86\u6D4B\u8BD5\u7528\u6237\u767B\u5F55\u529F\u80FD\uFF0C\u800C\u4EE5 GUI \u7684\u65B9\u5F0F\u5F53\u573A\u6CE8\u518C\u4E00\u4E2A\u65B0\u7528\u6237\u5417\uFF1F\u663E\u7136\uFF0C\u8FD9\u662F\u4E0D\u53EF\u53D6\u7684\u3002</p><p>\u5176\u5B9E\u4ECE\u8FD9\u91CC\uFF0C\u4F60\u5C31\u53EF\u4EE5\u770B\u51FA\u6D4B\u8BD5\u6570\u636E\u51C6\u5907\u662F\u5B9E\u73B0\u6D4B\u8BD5\u7528\u4F8B\u89E3\u8026\u7684\u91CD\u8981\u624B\u6BB5\uFF0C\u4F60\u5B8C\u5168\u4E0D\u5FC5\u4E3A\u4E86\u6D4B\u8BD5 GUI \u7528\u6237\u767B\u5F55\u529F\u80FD\u800C\u53BB\u6267\u884C\u7528\u6237\u6CE8\u518C\uFF0C\u53EA\u8981\u4F60\u80FD\u591F\u6709\u65B9\u6CD5\u5FEB\u901F\u521B\u5EFA\u51FA\u8FD9\u4E2A\u767B\u5F55\u7528\u6237\u5C31\u53EF\u4EE5\u4E86\u3002</p><p>\u5728\u6B63\u5F0F\u8BA8\u8BBA\u6D4B\u8BD5\u6570\u636E\u7684\u521B\u5EFA\u65B9\u6CD5\u524D\uFF0C\u6211\u5148\u6765\u5206\u6790\u4E00\u4E0B GUI \u6D4B\u8BD5\u4E2D\u4E24\u79CD\u5E38\u89C1\u7684\u6570\u636E\u7C7B\u578B\uFF1A</p><ul><li><p>\u7B2C\u4E00\u5927\u7C7B\u662F\uFF0C\u6D4B\u8BD5\u8F93\u5165\u6570\u636E\uFF0C\u4E5F\u5C31\u662F GUI \u6D4B\u8BD5\u8FC7\u7A0B\u4E2D\uFF0C\u901A\u8FC7\u754C\u9762\u8F93\u5165\u7684\u6570\u636E\u3002\u6BD4\u5982\u201C\u7528\u6237\u767B\u5F55\u201D\u6D4B\u8BD5\u4E2D\u8F93\u5165\u7684\u7528\u6237\u540D\u548C\u5BC6\u7801\u5C31\u5C31\u5C5E\u4E8E\u8FD9\u4E00\u7C7B\u6570\u636E\uFF1B\u518D\u6BD4\u5982\uFF0C\u6570\u636E\u9A71\u52A8\u6D4B\u8BD5\u4E2D\u7684\u6D4B\u8BD5\u6570\u636E\uFF0C\u4E5F\u662F\u6307\u8FD9\u4E00\u7C7B\u3002</p></li><li><p>\u7B2C\u4E8C\u5927\u7C7B\u662F\uFF0C\u4E3A\u4E86\u5B8C\u6210 GUI \u6D4B\u8BD5\u800C\u9700\u8981\u51C6\u5907\u7684\u6D4B\u8BD5\u6570\u636E\u3002\u6BD4\u5982\uFF0C\u201C\u7528\u6237\u767B\u5F55\u201D\u6D4B\u8BD5\u4E2D\uFF0C\u6211\u4EEC\u9700\u8981\u4E8B\u5148\u51C6\u5907\u597D\u7528\u6237\u8D26\u6237\uFF0C\u4EE5\u4FBF\u8FDB\u884C\u7528\u6237\u7684\u767B\u5F55\u6D4B\u8BD5\u3002\u4ECA\u5929\u6211\u5206\u4EAB\u7684\u6D4B\u8BD5\u6570\u636E\u521B\u5EFA\u7684\u65B9\u6CD5\uFF0C\u4E5F\u90FD\u662F\u56F4\u7740\u8FD9\u4E00\u90E8\u5206\u7684\u6570\u636E\u5C55\u5F00\u7684\u3002</p></li></ul><p>\u90A3\u4E48\u63A5\u4E0B\u6765\uFF0C\u6211\u5C31\u5E26\u4F60\u4E00\u8D77\u53BB\u770B\u770B\u521B\u5EFA\u6D4B\u8BD5\u6570\u636E\u7684\u65B9\u6CD5\u90FD\u6709\u54EA\u4E9B\uFF0C\u4EE5\u53CA\u5B83\u4EEC\u5404\u81EA\u7684\u4F18\u7F3A\u70B9\uFF0C\u548C\u9002\u7528\u573A\u666F\u3002</p><p>\u4ECE\u521B\u5EFA\u7684\u6280\u672F\u624B\u6BB5\u4E0A\u6765\u8BB2\uFF0C\u521B\u5EFA\u6D4B\u8BD5\u6570\u636E\u7684\u65B9\u6CD5\u4E3B\u8981\u5206\u4E3A\u4E09\u79CD\uFF1A</p><ol><li>API \u8C03\u7528\uFF1B</li><li>\u6570\u636E\u5E93\u64CD\u4F5C\uFF1B</li><li>\u7EFC\u5408\u8FD0\u7528 API \u8C03\u7528\u548C\u6570\u636E\u5E93\u64CD\u4F5C\u3002</li></ol><p>\u4ECE\u521B\u5EFA\u7684\u65F6\u673A\u6765\u8BB2\uFF0C\u521B\u5EFA\u6D4B\u8BD5\u6570\u636E\u7684\u65B9\u6CD5\u4E3B\u8981\u5206\u4E3A\u4E24\u79CD\uFF1A</p><ol><li>\u6D4B\u8BD5\u7528\u4F8B\u6267\u884C\u8FC7\u7A0B\u4E2D\uFF0C\u5B9E\u65F6\u521B\u5EFA\u6D4B\u8BD5\u6570\u636E\uFF0C\u6211\u4EEC\u901A\u5E38\u79F0\u8FD9\u79CD\u65B9\u5F0F\u4E3A On-the-fly\u3002</li><li>\u6D4B\u8BD5\u7528\u4F8B\u6267\u884C\u524D\uFF0C\u4E8B\u5148\u521B\u5EFA\u597D\u201C\u5F00\u7BB1\u5373\u7528\u201D\u7684\u6D4B\u8BD5\u6570\u636E\uFF0C\u6211\u4EEC\u901A\u5E38\u79F0\u8FD9\u79CD\u65B9\u5F0F\u4E3A Out-of-box\u3002</li></ol><p><strong>\u5728\u5B9E\u9645\u9879\u76EE\u4E2D\uFF0C\u5BF9\u4E8E\u521B\u5EFA\u6570\u636E\u7684\u6280\u672F\u624B\u6BB5\u800C\u8A00\uFF0C\u6700\u4F73\u7684\u9009\u62E9\u662F\u5229\u7528 API \u6765\u521B\u5EFA\u6570\u636E\uFF0C\u53EA\u6709\u5F53 API \u4E0D\u80FD\u6EE1\u8DB3\u6570\u636E\u521B\u5EFA\u7684\u9700\u6C42\u65F6\uFF0C\u624D\u4F1A\u4F7F\u7528\u6570\u636E\u5E93\u64CD\u4F5C\u7684\u624B\u6BB5</strong>\u3002</p><p><em>\u5B9E\u9645\u4E0A\uFF0C\u5F80\u5F80\u5F88\u591A\u6D4B\u8BD5\u6570\u636E\u7684\u521B\u5EFA\u662F\u57FA\u4E8E API \u548C\u6570\u636E\u5E93\u64CD\u4F5C\u4E24\u8005\u7684\u7ED3\u5408\u6765\u5B8C\u6210\uFF0C\u5373\u5148\u901A\u8FC7 API \u521B\u5EFA\u57FA\u672C\u7684\u6570\u636E\uFF0C\u7136\u540E\u8C03\u7528\u6570\u636E\u5E93\u64CD\u4F5C\u6765\u4FEE\u6539\u6570\u636E\uFF0C\u4EE5\u8FBE\u5230\u5BF9\u6D4B\u8BD5\u6570\u636E\u7684\u7279\u5B9A\u8981\u6C42</em>\u3002</p><p><strong>\u800C\u5BF9\u4E8E\u521B\u5EFA\u6570\u636E\u7684\u65F6\u673A\uFF0C\u5728\u5B9E\u9645\u9879\u76EE\u4E2D\uFF0C\u5F80\u5F80\u662F On-the-fly \u548C Out-of-box \u7ED3\u5408\u5728\u4E00\u8D77\u4F7F\u7528</strong>\u3002</p><p><em>\u5BF9\u4E8E\u76F8\u5BF9\u7A33\u5B9A\u7684\u6D4B\u8BD5\u6570\u636E\uFF0C\u6BD4\u5982\u5546\u54C1\u7C7B\u578B\u3001\u56FE\u4E66\u7C7B\u578B\u7B49\uFF0C\u5F80\u5F80\u91C7\u7528 Out-of-box \u7684\u65B9\u5F0F\u4EE5\u63D0\u9AD8\u6548\u7387\uFF1B\u800C\u5BF9\u4E8E\u90A3\u4E9B\u53EA\u80FD\u4E00\u6B21\u6027\u4F7F\u7528\u7684\u6D4B\u8BD5\u6570\u636E\uFF0C\u6BD4\u5982\u5546\u54C1\u3001\u8BA2\u5355\u3001\u4F18\u60E0\u5238\u7B49\uFF0C\u5F80\u5F80\u91C7\u7528 On-the-fly \u7684\u65B9\u5F0F\u4EE5\u4FDD\u8BC1\u4E0D\u5B58\u5728\u810F\u6570\u636E\u95EE\u9898</em>\u3002</p><p>\u63A5\u4E0B\u6765\uFF0C\u6211\u5C31\u5148\u4ECE\u6D4B\u8BD5\u6570\u636E\u521B\u5EFA\u7684\u6280\u672F\u624B\u6BB5\u5F00\u59CB\u4ECA\u5929\u7684\u5206\u4EAB\u5427\u3002</p><p><strong>\u57FA\u4E8E API \u8C03\u7528\u521B\u5EFA\u6D4B\u8BD5\u6570\u636E</strong></p><p>\u5148\u770B\u4E00\u4E2A\u7535\u5546\u7F51\u7AD9\u201C\u65B0\u7528\u6237\u6CE8\u518C\u201D\u7684\u4F8B\u5B50\uFF0C\u5F53\u7528\u6237\u901A\u8FC7 GUI \u754C\u9762\u5B8C\u6210\u65B0\u7528\u6237\u6CE8\u518C\u4FE1\u606F\u586B\u5199\u540E\uFF0C\u5411\u7CFB\u7EDF\u540E\u53F0\u9012\u4EA4\u8868\u5355\uFF0C\u7CFB\u7EDF\u540E\u53F0\u5C31\u4F1A\u8C03\u7528 createUser \u7684 API \u5B8C\u6210\u7528\u6237\u7684\u521B\u5EFA\u3002</p><p>\u800C\u4E92\u8054\u7F51\u4EA7\u54C1\uFF0C\u5C24\u5176\u662F\u73B0\u5728\u5927\u91CF\u91C7\u7528\u5FAE\u670D\u52A1\u67B6\u6784\u7684\u7F51\u7AD9\uFF0C\u8FD9\u4E2A API \u5F80\u5F80\u4EE5 Web Service \u7684\u5F62\u5F0F\u66B4\u9732\u63A5\u53E3\u3002\u90A3\u4E48\uFF0C\u5728\u8FD9\u79CD\u67B6\u6784\u4E0B\uFF0C\u4F60\u5B8C\u5168\u53EF\u4EE5\u76F4\u63A5\u8C03\u7528\u8FD9\u4E2A API \u6765\u521B\u5EFA\u65B0\u7528\u6237\uFF0C\u800C\u65E0\u987B\u518D\u5411\u540E\u53F0\u9012\u4EA4\u8868\u5355\u3002</p><p>\u7531\u4E8E API \u901A\u5E38\u90FD\u6709\u5B89\u5168\u76F8\u5173\u7684 token \u673A\u5236\u6765\u4FDD\u62A4\uFF0C\u6240\u4EE5\u5B9E\u9645\u9879\u76EE\u4E2D\uFF0C\u901A\u5E38\u4F1A\u628A\u5BF9\u8FD9\u4E9B API \u7684\u8C03\u7528\u4EE5\u4EE3\u7801\u7684\u5F62\u5F0F\u5C01\u88C5\u4E3A\u6D4B\u8BD5\u6570\u636E\u5DE5\u5177\uFF08Test Data Utility\uFF09\u3002</p><p>\u8FD9\u79CD\u65B9\u5F0F\u6700\u5927\u7684\u597D\u5904\u5C31\u662F\uFF0C\u6D4B\u8BD5\u6570\u636E\u7684\u51C6\u786E\u6027\u76F4\u63A5\u7531\u4EA7\u54C1 API \u4FDD\u8BC1\uFF0C\u7F3A\u70B9\u662F\u5E76\u4E0D\u662F\u6240\u6709\u7684\u6D4B\u8BD5\u6570\u636E\u90FD\u6709\u76F8\u5173\u7684 API \u6765\u652F\u6301\u3002</p><p>\u53E6\u5916\uFF0C\u5BF9\u9700\u8981\u5927\u91CF\u521B\u5EFA\u6570\u636E\u7684\u6D4B\u8BD5\u6765\u8BF4\uFF0C\u57FA\u4E8E API \u8C03\u7528\u65B9\u5F0F\u7684\u6267\u884C\u6548\u7387\uFF0C\u5373\u4F7F\u91C7\u7528\u4E86\u5E76\u53D1\u673A\u5236\u4E5F\u4E0D\u4F1A\u5341\u5206\u7406\u60F3\u3002\u4E3A\u4E86\u89E3\u51B3\u6267\u884C\u6548\u7387\u7684\u95EE\u9898\uFF0C\u5C31\u6709\u4E86\u57FA\u4E8E\u6570\u636E\u5E93\u64CD\u4F5C\u7684\u6D4B\u8BD5\u6570\u636E\u521B\u5EFA\u624B\u6BB5\u3002</p><p><strong>\u57FA\u4E8E\u6570\u636E\u5E93\u64CD\u4F5C\u521B\u5EFA\u6D4B\u8BD5\u6570\u636E</strong></p><p>\u5B9E\u9645\u9879\u76EE\u4E2D\uFF0C\u5E76\u4E0D\u662F\u6240\u6709\u7684\u6570\u636E\u90FD\u53EF\u4EE5\u901A\u8FC7 API \u7684\u65B9\u5F0F\u5B9E\u73B0\u521B\u5EFA\u548C\u4FEE\u6539\uFF0C\u5F88\u591A\u6570\u636E\u7684\u521B\u5EFA\u548C\u4FEE\u6539\u76F4\u63A5\u5728\u4EA7\u54C1\u4EE3\u7801\u5185\u5B8C\u6210\uFF0C\u800C\u4E14\u5E76\u6CA1\u6709\u5BF9\u5916\u66B4\u9732\u4F9B\u6D4B\u8BD5\u4F7F\u7528\u7684\u63A5\u53E3\u3002</p><p>\u90A3\u4E48\uFF0C\u8FD9\u79CD\u60C5\u51B5\u4E0B\uFF0C\u4F60\u5C31\u9700\u8981\u901A\u8FC7\u76F4\u63A5\u64CD\u4F5C\u6570\u636E\u5E93\u7684\u65B9\u5F0F\u6765\u4EA7\u751F\u6D4B\u8BD5\u6570\u636E\u3002</p><p>\u540C\u6837\u5730\uFF0C\u6211\u4EEC\u53EF\u4EE5\u628A\u521B\u5EFA\u548C\u4FEE\u6539\u6570\u636E\u7684\u76F8\u5173 SQL \u8BED\u53E5\u5C01\u88C5\u6210\u6D4B\u8BD5\u6570\u636E\u5DE5\u5177\uFF0C\u4EE5\u65B9\u4FBF\u6D4B\u8BD5\u7528\u4F8B\u7684\u4F7F\u7528\u3002\u4F46\u662F\uFF0C\u5982\u679C\u4F60\u6B63\u5C1D\u8BD5\u5728\u5B9E\u9645\u9879\u76EE\u4E2D\u8FD0\u7528\u8FD9\u4E2A\u65B9\u6CD5\uFF0C\u4E0D\u53EF\u907F\u514D\u5730\u4F1A\u9047\u5230\u5982\u4F55\u624D\u80FD\u627E\u5230\u6B63\u786E\u7684 SQL \u8BED\u53E5\u6765\u521B\u5EFA\u548C\u4FEE\u6539\u6570\u636E\u7684\u95EE\u9898\u3002</p><p>\u56E0\u4E3A\uFF0C\u521B\u5EFA\u6216\u4FEE\u6539\u4E00\u6761\u6D4B\u8BD5\u6570\u636E\u5F80\u5F80\u4F1A\u6D89\u53CA\u5F88\u591A\u4E1A\u52A1\u8868\uFF0C\u4EFB\u4F55\u7684\u9057\u6F0F\u90FD\u4F1A\u9020\u6210\u6D4B\u8BD5\u6570\u636E\u7684\u4E0D\u51C6\u786E\uFF0C\u4ECE\u800C\u5BFC\u81F4\u6709\u4E9B\u6D4B\u8BD5\u56E0\u4E3A\u6570\u636E\u95EE\u9898\u800C\u65E0\u6CD5\u8FDB\u884C\u3002</p><p>\u90A3\u4E48\uFF0C\u73B0\u5728\u6211\u5C31\u63D0\u4F9B\u4E24\u4E2A\u601D\u8DEF\u6765\u5E2E\u4F60\u89E3\u51B3\u8FD9\u4E2A\u95EE\u9898\uFF1A</p><ol><li>\u624B\u5DE5\u65B9\u5F0F\u3002\u67E5\u9605\u8BBE\u8BA1\u6587\u6863\u548C\u4EA7\u54C1\u4EE3\u7801\uFF0C\u627E\u5230\u76F8\u5173\u7684 SQL \u8BED\u53E5\u96C6\u5408\u3002\u6216\u8005\uFF0C\u76F4\u63A5\u627E\u5F00\u53D1\u4EBA\u5458\u7D22\u8981\u76F8\u5173\u7684 SQL \u8BED\u53E5\u96C6\u5408\u3002</li><li>\u81EA\u52A8\u65B9\u5F0F\u3002\u5728\u6D4B\u8BD5\u73AF\u5883\u4E2D\uFF0C\u5148\u5728\u53EA\u6709\u4E00\u4E2A\u6D3B\u8DC3\u7528\u6237\u7684\u60C5\u51B5\u4E0B\uFF0C\u901A\u8FC7 GUI \u754C\u9762\u64CD\u4F5C\u5B8C\u6210\u6570\u636E\u7684\u521B\u5EFA\u3001\u4FEE\u6539\uFF0C\u7136\u540E\u5229\u7528\u6570\u636E\u5E93\u76D1\u63A7\u5DE5\u5177\u83B7\u53D6\u8FD9\u6BB5\u65F6\u95F4\u5185\u6240\u6709\u7684\u4E1A\u52A1\u8868\u4FEE\u6539\u8BB0\u5F55\uFF0C\u4EE5\u6B64\u4E3A\u4F9D\u636E\u5F00\u53D1 SQL \u8BED\u53E5\u96C6\u3002</li></ol><p>\u9700\u8981\u6CE8\u610F\u7684\u662F\uFF0C\u8FD9\u4E24\u79CD\u601D\u8DEF\u7684\u524D\u63D0\u90FD\u662F\uFF0C\u5047\u5B9A\u4EA7\u54C1\u529F\u80FD\u6B63\u786E\uFF0C\u5426\u5219\u5C31\u4F1A\u51FA\u73B0\u201C\u4E00\u9519\u5230\u5E95\u201D\u7684\u5C34\u5C2C\u5C40\u9762\u3002</p><p>\u57FA\u4E8E\u6570\u636E\u5E93\u64CD\u4F5C\u521B\u5EFA\u6D4B\u8BD5\u6570\u636E\u7684\u6700\u5927\u597D\u5904\u662F\uFF0C\u53EF\u4EE5\u521B\u5EFA\u548C\u4FEE\u6539 API \u4E0D\u652F\u6301\u7684\u6D4B\u8BD5\u6570\u636E\uFF0C\u5E76\u4E14\u7531\u4E8E\u662F\u76F4\u63A5\u6570\u636E\u5E93\u64CD\u4F5C\uFF0C\u6267\u884C\u6548\u7387\u4F1A\u8FDC\u8FDC\u9AD8\u4E8E API \u8C03\u7528\u65B9\u6CD5\u3002</p><p>\u4F46\u662F\uFF0C\u6570\u636E\u5E93\u64CD\u4F5C\u8FD9\u79CD\u65B9\u5F0F\u7684\u7F3A\u70B9\u4E5F\u663E\u800C\u6613\u89C1\uFF0C\u6570\u636E\u5E93\u8868\u64CD\u4F5C\u7684\u4EFB\u4F55\u53D8\u66F4\uFF0C\u90FD\u5FC5\u987B\u540C\u6B65\u66F4\u65B0\u6D4B\u8BD5\u6570\u636E\u5DE5\u5177\u4E2D\u7684 SQL \u8BED\u53E5\u3002</p><p>\u4F46\u5F88\u4E0D\u5E78\u7684\u662F\uFF0C\u5728\u5B9E\u9645\u9879\u76EE\u4E2D\uFF0C\u7ECF\u5E38\u51FA\u73B0\u56E0\u4E3A SQL \u8BED\u53E5\u66F4\u65B0\u4E0D\u53CA\u65F6\u800C\u5BFC\u81F4\u6D4B\u8BD5\u6570\u636E\u9519\u8BEF\u7684\u95EE\u9898\uFF0C\u800C\u4E14\u8FD9\u91CC\u7684\u6570\u636E\u4E0D\u51C6\u786E\u5F80\u5F80\u53EA\u662F\u5C40\u90E8\u9519\u8BEF\uFF0C\u56E0\u6B64\u8FD9\u7C7B\u95EE\u9898\u5F80\u5F80\u6BD4\u8F83\u9690\u853D\uFF0C\u53EA\u6709\u5728\u7279\u5B9A\u7684\u6D4B\u8BD5\u573A\u666F\u4E0B\u624D\u4F1A\u66B4\u9732\u3002</p><p>\u6240\u4EE5\uFF0C\u5728\u5B9E\u9645\u5DE5\u7A0B\u9879\u76EE\u4E2D\uFF0C\u9700\u8981\u5F15\u5165\u6D4B\u8BD5\u6570\u636E\u5DE5\u5177\u7684\u7248\u672C\u7BA1\u7406\uFF0C\u5E76\u901A\u8FC7\u5F00\u53D1\u6D41\u7A0B\u6765\u4FDD\u8BC1 SQL \u7684\u53D8\u66F4\u80FD\u591F\u53CA\u65F6\u901A\u77E5\u5230\u6D4B\u8BD5\u6570\u636E\u5DE5\u5177\u56E2\u961F\u3002</p><p><strong>\u7EFC\u5408\u8FD0\u7528 API \u8C03\u7528\u548C\u6570\u636E\u5E93\u64CD\u4F5C\u521B\u5EFA\u6D4B\u8BD5\u6570\u636E</strong></p><p>\u4F60\u5982\u679C\u5DF2\u7ECF\u7406\u89E3\u4E86\u57FA\u4E8E API \u8C03\u7528\u548C\u57FA\u4E8E\u6570\u636E\u5E93\u64CD\u4F5C\u521B\u5EFA\u6D4B\u8BD5\u6570\u636E\u8FD9\u4E24\u7C7B\u65B9\u6CD5\uFF0C\u90A3\u4E48\u7EFC\u5408\u8FD0\u7528\u8FD9\u4E24\u7C7B\u65B9\u6CD5\uFF0C\u5C31\u662F\u4F7F\u5F97\u6D4B\u8BD5\u6570\u636E\u5DE5\u5177\u80FD\u591F\u63D0\u4F9B\u66F4\u591A\u79CD\u7C7B\u7684\u4E1A\u52A1\u6D4B\u8BD5\u6570\u636E\u3002</p><p>\u5177\u4F53\u6765\u8BB2\uFF0C\u5F53\u4F60\u8981\u521B\u5EFA\u4E00\u79CD\u7279\u5B9A\u7684\u6D4B\u8BD5\u6570\u636E\u65F6\uFF0C\u4F60\u53D1\u73B0\u6CA1\u6709\u76F4\u63A5 API \u652F\u6301\uFF0C\u4F46\u662F\u53EF\u4EE5\u901A\u8FC7 API \u5148\u521B\u5EFA\u4E00\u4E2A\u57FA\u672C\u7684\u6570\u636E\uFF0C\u7136\u540E\u518D\u901A\u8FC7\u4FEE\u6539\u6570\u636E\u5E93\u7684\u65B9\u5F0F\u6765\u66F4\u65B0\u8FD9\u4E2A\u6570\u636E\uFF0C\u4EE5\u6B64\u6765\u8FBE\u5230\u521B\u5EFA\u7279\u5B9A\u6D4B\u8BD5\u6570\u636E\u7684\u8981\u6C42\u3002</p><p>\u6BD4\u5982\uFF0C\u4F60\u9700\u8981\u521B\u5EFA\u4E00\u4E2A\u5DF2\u7ECF\u7ED1\u5B9A\u4E86\u4FE1\u7528\u5361\u7684\u65B0\u7528\u6237\uFF0C\u5982\u679C\u521B\u5EFA\u65B0\u7528\u6237\u6709\u76F4\u63A5\u7684 API\uFF0C\u800C\u7ED1\u5B9A\u4FE1\u7528\u5361\u9700\u8981\u64CD\u4F5C\u6570\u636E\u5E93\uFF0C\u90A3\u8FD9\u79CD\u60C5\u51B5\u4E0B\u5C31\u9700\u8981\u7EFC\u5408\u8FD0\u7528\u8FD9\u4E24\u79CD\u65B9\u5F0F\u5B8C\u6210\u6D4B\u8BD5\u6570\u636E\u5DE5\u5177\u7684\u5F00\u53D1\u3002</p><p><strong>\u5B9E\u65F6\u521B\u5EFA\u6570\u636E\uFF1AOn-the-fly</strong><strong>GUI \u6D4B\u8BD5\u811A\u672C\u4E2D\uFF0C\u5728\u5F00\u59CB\u6267\u884C\u754C\u9762\u64CD\u4F5C\u524D\uFF0C\u6211\u4EEC\u5F80\u5F80\u4F1A\u901A\u8FC7\u8C03\u7528\u6D4B\u8BD5\u6570\u636E\u5DE5\u5177\u5B9E\u65F6\u521B\u5EFA\u6D4B\u8BD5\u6570\u636E\uFF0C\u4E5F\u5C31\u662F On-the-fly \u65B9\u5F0F</strong>\u3002</p><p>\u8FD9\u79CD\u65B9\u5F0F\u4E0D\u4F9D\u8D56\u88AB\u6D4B\u8BD5\u7CFB\u7EDF\u4E2D\u7684\u4EFB\u4F55\u539F\u6709\u6570\u636E\uFF0C\u4E5F\u4E0D\u4F1A\u5BF9\u539F\u6709\u6570\u636E\u4EA7\u751F\u5F71\u54CD\uFF0C\u53EF\u4EE5\u5F88\u597D\u5730\u4ECE\u6570\u636E\u5C42\u9762\u9694\u79BB\u6D4B\u8BD5\u7528\u4F8B\uFF0C\u8BA9\u6D4B\u8BD5\u7528\u4F8B\u5B9E\u73B0\u201C\u81EA\u5305\u542B\u201D\u3002</p><p>\u4ECE\u7406\u8BBA\u4E0A\u8BB2\uFF0COn-the-fly \u662F\u5F88\u597D\u7684\u65B9\u6CD5\uFF0C\u4F46\u5728\u5B9E\u9645\u6D4B\u8BD5\u9879\u76EE\u4E2D\u5374\u5E76\u4E0D\u662F\u90A3\u4E48\u56DE\u4E8B\u513F\uFF0C\u5F80\u5F80\u4F1A\u5B58\u5728\u4E09\u4E2A\u95EE\u9898\uFF1A</p><ol><li>\u5728\u7528\u4F8B\u6267\u884C\u8FC7\u7A0B\u4E2D\u5B9E\u65F6\u521B\u5EFA\u6570\u636E\uFF0C\u5BFC\u81F4\u6D4B\u8BD5\u7684\u6267\u884C\u65F6\u95F4\u6BD4\u8F83\u957F\u3002 \u6211\u66FE\u7ECF\u7C97\u7565\u7EDF\u8BA1\u8FC7\u4E00\u4E2A\u5927\u578B Web GUI \u81EA\u52A8\u5316\u6D4B\u8BD5\u9879\u76EE\u7684\u6267\u884C\u65F6\u95F4\uFF0C\u5C06\u8FD1 30%\u7684\u65F6\u95F4\u90FD\u82B1\u5728\u4E86\u6D4B\u8BD5\u6570\u636E\u7684\u51C6\u5907\u4E0A\u3002</li><li>\u4E1A\u52A1\u6570\u636E\u7684\u8FDE\u5E26\u5173\u7CFB\uFF0C\u5BFC\u81F4\u6D4B\u8BD5\u6570\u636E\u7684\u521B\u5EFA\u6548\u7387\u975E\u5E38\u4F4E\u3002 \u6BD4\u5982\uFF0C\u4F60\u9700\u8981\u521B\u5EFA\u4E00\u4E2A\u8BA2\u5355\u6570\u636E\uFF0C\u800C\u8FD9\u4E2A\u8BA2\u5355\u5FC5\u7136\u4F1A\u7ED1\u5B9A\u4E70\u5BB6\u548C\u5356\u5BB6\uFF0C\u4EE5\u53CA\u8BA2\u5355\u5546\u54C1\u4FE1\u606F\u3002 \u5982\u679C\u5B8C\u5168\u57FA\u4E8E On-the-fly \u6A21\u5F0F\uFF0C\u4F60\u5C31\u9700\u8981\u5148\u5B9E\u65F6\u521B\u5EFA\u4E70\u5BB6\u548C\u5356\u5BB6\u8FD9\u4E24\u4E2A\u7528\u6237\uFF0C\u7136\u540E\u518D\u521B\u5EFA\u8BA2\u5355\u4E2D\u7684\u5546\u54C1\uFF0C\u6700\u540E\u624D\u662F\u521B\u5EFA\u8FD9\u4E2A\u8BA2\u5355\u672C\u8EAB\u3002 \u663E\u7136\uFF0C\u8FD9\u6837\u7684\u6D4B\u8BD5\u6570\u636E\u521B\u5EFA\u65B9\u5F0F\u867D\u7136\u662F\u201C\u81EA\u5305\u542B\u201D\u7684\uFF0C\u4F46\u521B\u5EFA\u6548\u7387\u975E\u5E38\u4F4E\uFF0C\u4F1A\u4F7F\u5F97\u6D4B\u8BD5\u7528\u4F8B\u6267\u884C\u65F6\u95F4\u53D8\u5F97\u66F4\u957F\uFF0C\u800C\u8FD9\u6070\u6070\u4E0E\u4E92\u8054\u7F51\u4EA7\u54C1\u7684\u6D4B\u8BD5\u7B56\u7565\u4EA7\u751F\u51B2\u7A81\u3002</li><li>\u66F4\u7CDF\u7CD5\u7684\u60C5\u51B5\u662F\uFF0C\u5B9E\u65F6\u521B\u5EFA\u6D4B\u8BD5\u6570\u636E\u7684\u65B9\u5F0F\u5BF9\u6D4B\u8BD5\u73AF\u5883\u7684\u4F9D\u8D56\u6027\u5F88\u5F3A\u3002 \u6BD4\u5982\uFF0C\u4F60\u8981\u6D4B\u8BD5\u7528\u6237\u767B\u5F55\u529F\u80FD\uFF0C\u57FA\u4E8E On-the-fly \u65B9\u5F0F\uFF0C\u4F60\u5C31\u5E94\u8BE5\u5148\u8C03\u7528\u6D4B\u8BD5\u6570\u636E\u5DE5\u5177\u5B9E\u65F6\u521B\u5EFA\u4E00\u4E2A\u7528\u6237\uFF0C\u7136\u540E\u518D\u7528\u8FD9\u4E2A\u7528\u6237\u5B8C\u6210\u767B\u5F55\u6D4B\u8BD5\u3002 \u8FD9\u65F6\uFF0C\u521B\u5EFA\u7528\u6237\u7684 API \u7531\u4E8E\u5404\u79CD\u539F\u56E0\u5904\u4E8E\u4E0D\u53EF\u7528\u7684\u72B6\u6001\uFF08\u8FD9\u79CD\u60C5\u51B5\u5728\u91C7\u7528\u5FAE\u670D\u52A1\u67B6\u6784\u7684\u7CFB\u7EDF\u4E2D\u5F88\u5E38\u89C1\uFF09\uFF0C\u90A3\u4E48\u8FD9\u65F6\u5C31\u4F1A\u56E0\u4E3A\u65E0\u6CD5\u521B\u5EFA\u7528\u6237\uFF0C\u800C\u65E0\u6CD5\u5B8C\u6210\u7528\u6237\u767B\u5F55\u6D4B\u8BD5\u3002</li></ol><p>\u57FA\u4E8E\u8FD9\u4E09\u79CD\u5E38\u89C1\u95EE\u9898\uFF0C\u5B9E\u9645\u9879\u76EE\u4E2D\u8FD8\u4F1A\u5F15\u5165 Out-of-box \u65B9\u5F0F\uFF08\u5373\u5728\u6267\u884C\u6D4B\u8BD5\u7528\u4F8B\u524D\uFF0C\u9884\u5148\u521B\u5EFA\u597D\u6D4B\u8BD5\u6570\u636E\uFF09\u51C6\u5907\u6D4B\u8BD5\u6570\u636E\u3002</p><p><strong>\u4E8B\u5148\u521B\u5EFA\u6D4B\u8BD5\u6570\u636E\uFF1AOut-of-box</strong><strong>Out-of-box \u7684\u542B\u4E49\u662F\u5F00\u7BB1\u5373\u7528\uFF0C\u4E5F\u5C31\u662F\u8BF4\uFF0C\u5DF2\u7ECF\u5728\u88AB\u6D4B\u7CFB\u7EDF\u4E2D\u9884\u5148\u521B\u5EFA\u597D\u4E86\u5145\u8DB3\u7684\u3001\u5178\u578B\u7684\u6D4B\u8BD5\u6570\u636E\u3002\u8FD9\u4E9B\u6570\u636E\u901A\u5E38\u662F\u5728\u642D\u5EFA\u6D4B\u8BD5\u73AF\u5883\u65F6\u901A\u8FC7\u6570\u636E\u5E93\u811A\u672C\u201C\u9884\u57CB\u201D\u5728\u7CFB\u7EDF\u4E2D\u7684\uFF0C\u540E\u7EED\u7684\u6D4B\u8BD5\u7528\u4F8B\u53EF\u4EE5\u76F4\u63A5\u4F7F\u7528</strong>\u3002</p><p>Out-of-box \u7684\u65B9\u5F0F\u6709\u6548\u89E3\u51B3\u4E86 On-the-fly \u7684\u5F88\u591A\u95EE\u9898\uFF0C\u4F46\u662F\u8FD9\u79CD\u65B9\u6CD5\u7684\u7F3A\u70B9\u4E5F\u5F88\u660E\u663E\uFF0C\u4E3B\u8981\u4F53\u73B0\u5728\u4EE5\u4E0B\u4E09\u4E2A\u65B9\u9762\uFF1A</p><ol><li><strong>\u6D4B\u8BD5\u7528\u4F8B\u4E2D\u9700\u8981\u786C\u7F16\u7801\uFF08hardcode\uFF09\u6D4B\u8BD5\u6570\u636E\uFF0C\u989D\u5916\u5F15\u5165\u4E86\u6D4B\u8BD5\u6570\u636E\u548C\u7528\u4F8B\u4E4B\u95F4\u7684\u4F9D\u8D56</strong>\u3002</li><li><strong>\u53EA\u80FD\u88AB\u4E00\u6B21\u6027\u4F7F\u7528\u7684\u6D4B\u8BD5\u6570\u636E\u4E0D\u9002\u5408 Out-of-box \u7684\u65B9\u5F0F</strong>\u3002 \u6D4B\u8BD5\u7528\u4F8B\u5F80\u5F80\u4F1A\u9700\u8981\u4FEE\u6539\u6D4B\u8BD5\u6570\u636E\uFF0C\u800C\u4E14\u6709\u4E9B\u6D4B\u8BD5\u6570\u636E\u53EA\u80FD\u88AB\u4E00\u6B21\u6027\u4F7F\u7528\u3002\u6BD4\u5982\uFF0C\u4E00\u4E2A\u5546\u54C1\u88AB\u4E70\u4E0B\u4E00\u6B21\u540E\u5C31\u4E0D\u80FD\u518D\u7528\u4E86\uFF1B\u518D\u6BD4\u5982\uFF0C\u4F18\u60E0\u5238\u5728\u4E00\u4E2A\u8BA2\u5355\u4E2D\u88AB\u4F7F\u7528\u540E\uFF0C\u5C31\u5931\u6548\u4E86\uFF0C\u7B49\u7B49\u3002\u6240\u4EE5\u5982\u679C\u6CA1\u6709\u5F88\u597D\u7684\u5168\u5C40\u6D4B\u8BD5\u6570\u636E\u7BA1\u7406\uFF0C\u5F88\u5BB9\u6613\u56E0\u4E3A\u6D4B\u8BD5\u6570\u636E\u5931\u6548\u800C\u9020\u6210\u6D4B\u8BD5\u5931\u8D25\u3002</li><li><strong>\u201C\u9884\u57CB\u201D\u7684\u6D4B\u8BD5\u6570\u636E\u7684\u53EF\u9760\u6027\u8FDC\u4E0D\u5982\u5B9E\u65F6\u521B\u5EFA\u7684\u6570\u636E</strong>\u3002 \u5728\u6D4B\u8BD5\u7528\u4F8B\u6267\u884C\u8FC7\u7A0B\u4E2D\uFF0C\u7ECF\u5E38\u4F1A\u51FA\u73B0\u6D4B\u8BD5\u6570\u636E\u88AB\u4FEE\u6539\u7684\u60C5\u51B5\u3002\u6BD4\u5982\uFF0C\u624B\u52A8\u6D4B\u8BD5\uFF0C\u6216\u8005\u662F\u81EA\u52A8\u5316\u6D4B\u8BD5\u7528\u4F8B\u7684\u8C03\u8BD5\u7B49\u60C5\u51B5\u3002</li></ol><p><strong>On-the-fly \u548C Out-of-box \u7684\u4E92\u8865</strong></p><p>\u57FA\u4E8E On-the-fly \u548C Out-of-box \u7684\u4F18\u7F3A\u70B9\u548C\u4E92\u8865\u6027\uFF0C\u5728\u5B9E\u9645\u7684\u5927\u578B\u6D4B\u8BD5\u9879\u76EE\u4E2D\uFF0C\u6211\u4EEC\u5F80\u5F80\u4F1A\u91C7\u7528\u4E24\u8005\u76F8\u7ED3\u5408\u7684\u65B9\u5F0F\uFF0C\u4ECE\u6D4B\u8BD5\u6570\u636E\u672C\u8EAB\u7684\u7279\u70B9\u5165\u624B\uFF0C\u9009\u53D6\u4E0D\u540C\u7684\u6D4B\u8BD5\u6570\u636E\u521B\u5EFA\u65B9\u5F0F\u3002</p><p>\u9488\u5BF9\u5E94\u8BE5\u9009\u62E9\u4EC0\u4E48\u65F6\u673A\u521B\u5EFA\u6D4B\u8BD5\u6570\u636E\uFF0C\u7ED3\u5408\u591A\u5E74\u7684\u5B9E\u8DF5\u7ECF\u9A8C\uFF0C\u6211\u4E3A\u4F60\u603B\u7ED3\u4E86\u4EE5\u4E0B\u4E09\u70B9\uFF1A</p><ol><li>\u5BF9\u4E8E\u76F8\u5BF9\u7A33\u5B9A\u3001\u5F88\u5C11\u6709\u4FEE\u6539\u7684\u6570\u636E\uFF0C\u5EFA\u8BAE\u91C7\u7528 Out-of-box \u7684\u65B9\u5F0F\uFF0C\u6BD4\u5982\u5546\u54C1\u7C7B\u76EE\u3001\u5382\u5546\u54C1\u724C\u3001\u90E8\u5206\u6807\u51C6\u7684\u5356\u5BB6\u548C\u4E70\u5BB6\u8D26\u53F7\u7B49\u3002</li><li>\u5BF9\u4E8E\u4E00\u6B21\u6027\u4F7F\u7528\u3001\u7ECF\u5E38\u9700\u8981\u4FEE\u6539\u3001\u72B6\u6001\u7ECF\u5E38\u53D8\u5316\u7684\u6570\u636E\uFF0C\u5EFA\u8BAE\u4F7F\u7528 On-the-fly \u7684\u65B9\u5F0F\u3002</li><li>\u7528 On-the-fly \u65B9\u5F0F\u521B\u5EFA\u6D4B\u8BD5\u6570\u636E\u65F6\uFF0C\u4E0A\u6E38\u6570\u636E\u7684\u521B\u5EFA\u53EF\u4EE5\u91C7\u7528 Out-of-box \u65B9\u5F0F\uFF0C\u4EE5\u63D0\u9AD8\u6D4B\u8BD5\u6570\u636E\u521B\u5EFA\u7684\u6548\u7387\u3002\u4EE5\u8BA2\u5355\u6570\u636E\u4E3A\u4F8B\uFF0C\u8BA2\u5355\u7684\u521B\u5EFA\u53EF\u4EE5\u91C7\u7528 On-the-fly \u65B9\u5F0F\uFF0C\u800C\u4E0E\u8BA2\u5355\u76F8\u5173\u8054\u7684\u5356\u5BB6\u3001\u4E70\u5BB6\u548C\u5546\u54C1\u4FE1\u606F\u53EF\u4EE5\u4F7F\u7528 Out-of-box \u65B9\u5F0F\u521B\u5EFA\u3002</li></ol><p>\u5176\u5B9E\uFF0C\u4E3A\u4E86\u66F4\u597D\u5730\u89E3\u51B3\u6D4B\u8BD5\u6570\u636E\u672C\u8EAB\u7EC4\u5408\u7684\u590D\u6742\u6027\u548C\u591A\u6837\u6027\uFF0C\u5145\u5206\u53D1\u6325\u6D4B\u8BD5\u6570\u636E\u5DE5\u5177\u7684\u5A01\u529B\uFF0C\u8FD8\u6709\u5F88\u591A\u5927\u578B\u4F01\u4E1A\u7684\u6700\u4F73\u5B9E\u8DF5\u503C\u5F97\u8BA8\u8BBA\uFF0C\u5728\u672C\u4E13\u680F\u540E\u9762\u7684\u6D4B\u8BD5\u6570\u636E\u7AE0\u8282\uFF0C\u6211\u4F1A\u518D\u4E3A\u4F60\u8BE6\u7EC6\u4ECB\u7ECD\u3002</p><p><strong>\u603B\u7ED3</strong></p><p>\u4ECA\u5929\u6211\u4ECE\u521B\u5EFA\u6D4B\u8BD5\u6570\u636E\u7684\u6280\u672F\u624B\u6BB5\u548C\u65F6\u673A\u4E24\u4E2A\u65B9\u9762\uFF0C\u4ECB\u7ECD\u4E86 GUI \u6D4B\u8BD5\u6570\u636E\u7684\u51C6\u5907\u3002</p><p>\u5728\u5B9E\u9645\u6D4B\u8BD5\u9879\u76EE\u4E2D\uFF0C\u5F80\u5F80\u9700\u8981\u7EFC\u5408\u8FD0\u7528 API \u8C03\u7528\u548C\u6570\u636E\u5E93\u64CD\u4F5C\u6765\u521B\u5EFA\u6D4B\u8BD5\u6570\u636E\uFF0C\u5E76\u4E14\u4F1A\u6839\u636E\u6D4B\u8BD5\u6570\u636E\u81EA\u8EAB\u7684\u7279\u70B9\uFF0C\u5206\u800C\u6CBB\u4E4B\u5730\u91C7\u7528 On-the-fly \u548C Out-of-box \u7684\u65B9\u5F0F\uFF0C\u4EE5\u5BFB\u6C42\u6570\u636E\u7A33\u5B9A\u6027\u548C\u6570\u636E\u51C6\u5907\u6548\u7387\u4E4B\u95F4\u7684\u6700\u4F73\u5E73\u8861\u3002</p><p><strong>\u601D\u8003\u9898</strong></p><p>\u4F60\u6240\u5728\u7684\u516C\u53F8\u662F\u5982\u4F55\u51C6\u5907 GUI \u6D4B\u8BD5\u7684\u6D4B\u8BD5\u6570\u636E\u7684\uFF1F\u9047\u5230\u4E86\u54EA\u4E9B\u95EE\u9898\uFF0C\u5BF9\u5E94\u7684\u6709\u54EA\u4E9B\u89E3\u51B3\u65B9\u6848\u5462\uFF1F</p>',57);function n(i,r){return l}var s=p(t,[["render",n],["__file","15.html.vue"]]);export{s as default};
